def get_client_identifier():
    """Get unique client identifier from request"""
    # Use X-Forwarded-For if behind proxy, otherwise use remote_addr
    forwarded_for = request.headers.get('X-Forwarded-For')
    if forwarded_for:
        client_ip = forwarded_for.split(',')[0].strip()
    else:
        client_ip = request.remote_addr
    
    # Include user agent for better fingerprinting
    user_agent = request.headers.get('User-Agent', '')
    identifier = f"{client_ip}:{hashlib.md5(user_agent.encode()).hexdigest()[:8]}"
    return identifier


def rate_limit(max_requests=RATE_LIMIT_MAX_REQUESTS, window=RATE_LIMIT_WINDOW):
    """Rate limiting decorator using sliding window algorithm"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            identifier = get_client_identifier()
            key = f"rate_limit:{identifier}"
            
            try:
                current_time = time.time()
                
                # Remove old entries outside the window
                redis_client.zremrangebyscore(key, 0, current_time - window)
                
                # Count requests in current window
                request_count = redis_client.zcard(key)
                
                if request_count >= max_requests:
                    return jsonify({
                        'error': 'Rate limit exceeded',
                        'message': f'Maximum {max_requests} requests per {window} seconds allowed'
                    }), 429
                
                # Add current request
                redis_client.zadd(key, {str(current_time): current_time})
                redis_client.expire(key, window)
                
                # Add rate limit headers
                response = f(*args, **kwargs)
                if isinstance(response, tuple):
                    response_obj, status_code = response[0], response[1]
                else:
                    response_obj, status_code = response, 200
                
                if hasattr(response_obj, 'headers'):
                    response_obj.headers['X-RateLimit-Limit'] = str(max_requests)
                    response_obj.headers['X-RateLimit-Remaining'] = str(max_requests - request_count - 1)
                    response_obj.headers['X-RateLimit-Reset'] = str(int(current_time + window))
                
                return response_obj, status_code
                
            except redis.RedisError:
                # If Redis fails, allow the request but log the error
                app.logger.error(f"Redis error in rate limiting for {identifier}")
                return f(*args, **kwargs)
        
        return wrapped
    return decorator


def anti_enumeration():
    """Anti-enumeration protection decorator"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            identifier = get_client_identifier()
            block_key = f"blocked:{identifier}"
            enum_key = f"enumeration:{identifier}"
            
            try:
                # Check if client is blocked
                if redis_client.exists(block_key):
                    ttl = redis_client.ttl(block_key)
                    return jsonify({
                        'error': 'Access temporarily blocked',
                        'message': 'Too many requests detected. Please try again later.',
                        'retry_after': ttl
                    }), 403
                
                current_time = time.time()
                
                # Track enumeration attempts
                redis_client.zremrangebyscore(enum_key, 0, current_time - ENUMERATION_WINDOW)
                attempt_count = redis_client.zcard(enum_key)
                
                if attempt_count >= ENUMERATION_THRESHOLD:
                    # Block the client
                    redis_client.setex(block_key, ENUMERATION_BLOCK_TIME, '1')
                    app.logger.warning(f"Client {identifier} blocked for enumeration")
                    return jsonify({
                        'error': 'Access blocked',
                        'message': 'Suspicious activity detected. Access temporarily blocked.',
                        'retry_after': ENUMERATION_BLOCK_TIME
                    }), 403
                
                # Record this attempt
                redis_client.zadd(enum_key, {str(current_time): current_time})
                redis_client.expire(enum_key, ENUMERATION_WINDOW)
                
                return f(*args, **kwargs)
                
            except redis.RedisError:
                app.logger.error(f"Redis error in anti-enumeration for {identifier}")
                return f(*args, **kwargs)
        
        return wrapped
    return decorator


def sanitize_query(query):
    """Sanitize search query to prevent injection attacks"""
    if not query:
        return ""
    
    # Remove special Elasticsearch characters that could be used maliciously
    dangerous_chars = ['\\', '/', '&&', '||', '!', '(', ')', '{', '}', '[', ']', '^', '"', '~', '*', '?', ':']
    sanitized = query
    for char in dangerous_chars:
        sanitized = sanitized.replace(char, ' ')
    
    # Limit query length
    max_length = 200
    sanitized = sanitized[:max_length]
    
    # Remove excessive whitespace
    sanitized = ' '.join(sanitized.split())
    
    return sanitized


