def search_products():
    """Search products endpoint with rate limiting and anti-enumeration"""
    
    # Get query parameter
    query = request.args.get('q', '').strip()
    
    if not query:
        return jsonify({
            'error': 'Missing query parameter',
            'message': 'Please provide a search query using the "q" parameter'
        }), 400
    
    # Validate query length
    if len(query) < 2:
        return jsonify({
            'error': 'Invalid query',
            'message': 'Search query must be at least 2 characters long'
        }), 400
    
    # Sanitize query
    sanitized_query = sanitize_query(query)
    
    if not sanitized_query:
        return jsonify({
            'error': 'Invalid query',
            'message': 'Search query contains invalid characters'
        }), 400
    
    # Pagination parameters
    page = request.args.get('page', 1, type=int)
    per_page = request.args.get('per_page', 20, type=int)
    
    # Limit per_page to prevent abuse
    per_page = min(per_page, 100)
    page = max(page, 1)
    
    from_index = (page - 1) * per_page
    
    try:
        # Build Elasticsearch query
        search_body = {
            'query': {
                'multi_match': {
                    'query': sanitized_query,
                    'fields': ['name^3', 'description^2', 'category', 'tags', 'brand'],
                    'type': 'best_fields',
                    'fuzziness': 'AUTO'
                }
            },
            'from': from_index,
            'size': per_page,
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<mark>'],
                'post_tags': ['</mark>']
            },
            '_source': ['id', 'name', 'description', 'price', 'category', 'brand', 'image_url', 'in_stock']
        }
        
        # Execute search
        response = es.search(index=ELASTICSEARCH_INDEX, body=search_body)
        
        # Format results
        hits = response['hits']
        total = hits['total']['value'] if isinstance(hits['total'], dict) else hits['total']
        
        products = []
        for hit in hits['hits']:
            product = hit['_source']
            product['score'] = hit['_score']
            
            # Add highlights if available
            if 'highlight' in hit:
                product['highlights'] = hit['highlight']
            
            products.append(product)
        
        # Calculate pagination info
        total_pages = (total + per_page - 1) // per_page
        
        result = {
            'query': sanitized_query,
            'total': total,
            'page': page,
            'per_page': per_page,
            'total_pages': total_pages,
            'products': products
        }
        
        return jsonify(result), 200
        
    except Exception as e:
        app.logger.error(f"Search error: {str(e)}")
        return jsonify({
            'error': 'Search failed',
            'message': 'An error occurred while processing your search'
        }), 500


